Here's a complete MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        // Arrange
        using var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.InternalServerError,
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        using var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        // Arrange — handler that delays longer than [Timeout]
        using var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK),
            responseDelay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — TestContext.CancellationToken fires at 1 s
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    /// <summary>Minimal handler that returns a canned response.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response, TimeSpan responseDelay = default)
        {
            _response = response;
            _delay = responseDelay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return _response;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| `Assert.ThrowsExactlyAsync` | Matches exact exception type (HTTP error case) |
| `Assert.ThrowsAsync` | Matches `OperationCanceledException` *or* derived `TaskCanceledException` (both are valid cancellation outcomes) |
| `FakeHandler` | Avoids network calls by stubbing `HttpMessageHandler` directly |
| Pre-cancelled `CancellationTokenSource` | Tests the immediate-cancellation path without timing dependencies |

The slow-response test is the important one to get right — passing `_testContext.CancellationToken` into `FetchAsync` lets the `[Timeout(1000)]` attribute actually cancel the call instead of just failing the test after the full delay.
